+export const SCALE_STEPS = [1.0, 0.75, 0.5, 0.25];
+export const MIN_SCALE = SCALE_STEPS[SCALE_STEPS.length - 1];
+export const MAX_SCALE = SCALE_STEPS[0];
+
+// Window type constants (from Meta.WindowType enum).
+// Defined as raw integers so this file can be imported outside GNOME Shell
+// (e.g., by the standalone test runner).
+export const WINDOW_TYPE_NORMAL = 0;
+export const WINDOW_TYPE_DIALOG = 3;
+
+export const BATCH_SHRINK_LIMIT = 5;
+export const MONITOR_CACHE_TTL_MS = 30 * 60 * 1000; // 30 minutes
+
+/**
+ * Return the next scale step up from the given scale.
+ * Returns the same scale if already at max.
+ */
+export function scaleStepUp(current) {
+    for (let i = SCALE_STEPS.length - 1; i >= 0; i--) {
+        if (SCALE_STEPS[i] > current + 0.001)
+            return SCALE_STEPS[i];
+    }
+    return MAX_SCALE;
+}
+
+/**
+ * Return the next scale step down from the given scale.
+ * Returns the same scale if already at min.
+ */
+export function scaleStepDown(current) {
+    for (let i = 0; i < SCALE_STEPS.length; i++) {
+        if (SCALE_STEPS[i] < current - 0.001)
+            return SCALE_STEPS[i];
+    }
+    return MIN_SCALE;
+}
+
+/**
+ * Sanitize a connector name for use in dconf paths.
+ * Replaces anything outside [a-zA-Z0-9-] with '_'.
+ */
+export function sanitizeConnector(name) {
+    return name.replace(/[^a-zA-Z0-9-]/g, '_');
+}

